<template><view class="page"><view class="tabs"><view v-for="tab in tabs" :key="tab.key" :class="{active:tab.key===tabKey}" @click="change(tab.key)">{{tab.name}}</view></view><view v-if="tabKey==='center'" class="activity-note">活动券和可领取优惠券会在这里展示，领取后可在租车或汽车服务下单时使用。</view><view v-if="loading" class="empty">优惠券读取中</view><view v-else-if="items.length" class="list"><view v-for="item in items" :key="item.id" class="coupon"><view class="coupon-main"><text class="coupon-value">{{value(item)}}</text><text class="coupon-name">{{item.coupon_name}}</text></view><view class="coupon-info"><text>{{item.coupon_type_text||typeName(item)}} · {{item.applicable_business_text||'适用于租车订单'}}</text><text v-if="Number(item.threshold_amount)>0">满 ¥{{item.threshold_amount}} 可用</text><text v-if="tabKey!=='center'">有效期至 {{item.valid_end_at||'长期有效'}}</text><text v-if="tabKey==='locked'" class="locked-note">已在待支付订单中冻结</text><button v-if="tabKey==='center'" class="receive" :disabled="!item.can_receive" @click="receive(item)">{{item.can_receive?'立即领取':'已领取'}}</button></view></view></view><view v-else class="empty">暂无{{tabKey==='center'?'可领取':'优惠券'}}</view></view></template>
<script setup>import{ref}from'vue';import{onShow}from'@dcloudio/uni-app';import{getCouponCenter,getCoupons,receiveCoupon}from'../../api/member';const tabs=[{key:'center',name:'领券中心'},{key:'unused',name:'可用'},{key:'locked',name:'已冻结'},{key:'used',name:'已使用'},{key:'expired',name:'已失效'}],tabKey=ref('center'),items=ref([]),loading=ref(false);const typeName=i=>i.coupon_type==='discount'?'折扣券':i.coupon_type==='cash'?'代金券':'满减券';const value=i=>i.coupon_type==='discount'?`${Number(i.discount_rate)*10}折`:`¥${i.discount_amount}`;const load=async()=>{loading.value=true;try{const r=tabKey.value==='center'?await getCouponCenter():await getCoupons(tabKey.value);items.value=r.data?.data||[]}catch(e){uni.showToast({title:e.msg||'读取失败',icon:'none'})}finally{loading.value=false}};const change=k=>{if(tabKey.value===k)return;tabKey.value=k;load()};const receive=async item=>{try{await receiveCoupon(item.id);uni.showToast({title:'领取成功',icon:'success'});load()}catch(e){uni.showToast({title:e.msg||'领取失败',icon:'none'})}};onShow(load)</script>
<style scoped>.page{min-height:100vh;background:#f5f7fa}.tabs{display:flex;overflow-x:auto;background:#fff}.tabs view{flex:0 0 auto;padding:26rpx 22rpx;color:#6b7280;text-align:center;font-size:24rpx;white-space:nowrap}.tabs view.active{border-bottom:4rpx solid #1677ff;color:#1677ff;font-weight:700}.activity-note{margin:18rpx 32rpx;padding:16rpx;border-radius:6rpx;background:#eff6ff;color:#3b82f6;font-size:21rpx;line-height:1.5}.list{display:flex;flex-direction:column;gap:18rpx;padding:24rpx 32rpx}.coupon{display:flex;overflow:hidden;border-radius:8rpx;background:#fff}.coupon-main{display:flex;flex:0 0 190rpx;align-items:center;justify-content:center;flex-direction:column;padding:22rpx 12rpx;background:#e8f1ff;color:#1677ff}.coupon-value{font-size:36rpx;font-weight:700}.coupon-name{margin-top:10rpx;font-size:21rpx;text-align:center}.coupon-info{display:flex;flex:1;justify-content:center;flex-direction:column;gap:10rpx;padding:22rpx;color:#6b7280;font-size:22rpx}.locked-note{color:#c2410c}.receive{align-self:flex-start;margin:4rpx 0 0;padding:0 18rpx;border-radius:6rpx;background:#1677ff;color:#fff;font-size:21rpx;line-height:52rpx}.receive[disabled]{background:#cbd5e1}.empty{padding:180rpx 0;color:#9ca3af;text-align:center;font-size:26rpx}</style>
